/// <summary>
/// Contract class for ETG Ledger Voucher Transaction Details SSRS Report
/// </summary>
[DataContractAttribute]
public class ETGLedgerVoucherTransactionDetailsContract implements SysOperationValidatable
{
    TransDate fromDate;
    TransDate toDate;
    boolean filterByCreatedDate;
    NoYes myYesNoParameter;

}

Method.Source:
[DataMemberAttribute('FromDate'),
 SrsReportParameterAttribute(classStr(SrsReportParameterAttribute))]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[DataMemberAttribute('ToDate'),
 SrsReportParameterAttribute(classStr(SrsReportParameterAttribute))]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[DataMemberAttribute('FilterByCreatedDate'),
 SrsReportParameterAttribute(classStr(SrsReportParameterAttribute))]
public boolean parmFilterByCreatedDate(boolean _filterByCreatedDate = filterByCreatedDate)
{
    filterByCreatedDate = _filterByCreatedDate;
    return filterByCreatedDate;
}

[DataMemberAttribute('MyYesNoParameter')]
public NoYes parmMyYesNoParameter(NoYes _myYesNoParameter = myYesNoParameter)
{
    myYesNoParameter = _myYesNoParameter;
    return myYesNoParameter;
}

/// <summary>
/// Validates the contract parameters
/// </summary>
/// <returns>True if validation passes, false otherwise</returns>
public boolean validate()
{
    boolean isValid = true;

    if (!fromDate)
    {
        isValid = checkFailed("From date is required.");
    }

    if (!toDate)
    {
        isValid = checkFailed("To date is required.");
    }

    if (fromDate && toDate && fromDate > toDate)
    {
        isValid = checkFailed("From date cannot be greater than to date.");
    }

    return isValid;
}
